import { Component, Input, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-score-ring',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './score-ring.component.html',
  styleUrl: './score-ring.component.scss'
})
export class ScoreRingComponent implements OnInit {
  @Input() score: number = 0;
  
  circumference = 2 * Math.PI * 54; // radius = 54
  strokeDashoffset = this.circumference;

  ngOnInit() {
    const progress = this.score / 100;
    this.strokeDashoffset = this.circumference * (1 - progress);
  }

  getScoreColor(): string {
    if (this.score > 70) return 'success';
    if (this.score >= 40) return 'warning';
    return 'danger';
  }
}
<div class="score-ring">
  <svg width="140" height="140" viewBox="0 0 140 140">
    <circle
      class="score-ring-bg"
      cx="70"
      cy="70"
      r="54"
      fill="none"
      stroke-width="12"
    />
    <circle
      class="score-ring-progress"
      [attr.class]="'score-ring-progress ' + getScoreColor()"
      cx="70"
      cy="70"
      r="54"
      fill="none"
      stroke-width="12"
      [attr.stroke-dasharray]="circumference"
      [attr.stroke-dashoffset]="strokeDashoffset"
      transform="rotate(-90 70 70)"
    />
  </svg>
  <div class="score-value" [ngClass]="getScoreColor()">
    {{ score }}
  </div>
</div>
